-- Turkish Mechanic Shop - Server Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal RepairServices = {\n    {item = 'repair_kit', label = 'Tamir Seti', price = 500, time = 5},\n    {item = 'engine_part', label = 'Motor Parcasi', price = 2000, time = 15},\n}\n\nlocal TuningServices = {\n    {item = 'turbo', label = 'Turbo', price = 5000, performance = 1.2},\n    {item = 'nitrous', label = 'Nitro Sistemi', price = 8000, performance = 1.5},\n}\n\nRegisterNetEvent('mechanic:server:repairVehicle')\nAddEventHandler('mechanic:server:repairVehicle', function(vehicle, service)\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player then return end\n    \n    for i, repair in ipairs(RepairServices) do\n        if repair.item == service then\n            if Player.Functions.GetItemByName(service) then\n                Player.Functions.RemoveItem(service, 1)\n                TriggerClientEvent('QBCore:Notify', src, repair.label .. ' tamir basladi...', 'info')\n                return\n            end\n        end\n    end\nend)\n\nprint('^2[Turkish Mechanic Shop] Yuklendi!^7')"